# --- Context for Resolvers ---
class CustomContext(strawberry.fastapi.SyncGraphQLContext):
    def __init__(self, db_session: AsyncSession):
        super().__init__()
        self.db = db_session

async def get_db_session():
    async with AsyncSessionLocal() as session:
        yield session

# --- GraphQL Query Type ---
@strawberry.type
class Query:
    @strawberry.field
    async def products(
        self,
        info: strawberry.Info,
        limit: Optional[int] = 10,
        offset: Optional[int] = 0,
        name_contains: Optional[str] = None,
        category_id: Optional[int] = None,
        seller_id: Optional[int] = None,
    ) -> List[Product]:
        session: AsyncSession = info.context.db

        stmt = sa.select(SQLA_Product)

        if name_contains:
            stmt = stmt.where(SQLA_Product.name.ilike(f"%{name_contains}%"))
        if category_id:
            stmt = stmt.where(SQLA_Product.category_id == category_id)
        if seller_id:
            stmt = stmt.where(SQLA_Product.seller_id == seller_id)

        stmt = stmt.offset(offset).limit(limit)

        # Eagerly load category and seller for the main product query to avoid N+1
        # for these direct relationships.
        # Reviews and images are left to lazy load, allowing clients to request
        # them only when needed without pre-fetching all associated data.
        # SQLAlchemy's lazy loading will handle these when accessed through the Strawberry type.
        stmt = stmt.options(
            selectinload(SQLA_Product.category),
            selectinload(SQLA_Product.seller),
        )

        result = await session.execute(stmt)
        products = result.scalars().unique().all()
        return products

    @strawberry.field
    async def product(self, info: strawberry.Info, product_id: int) -> Optional[Product]:
        session: AsyncSession = info.context.db
        stmt = sa.select(SQLA_Product).where(SQLA_Product.id == product_id).options(
            selectinload(SQLA_Product.category),
            selectinload(SQLA_Product.seller),
            selectinload(SQLA_Product.reviews),
            selectinload(SQLA_Product.images),
        )
        result = await session.execute(stmt)
        return result.scalars().first()

    @strawberry.field
    async def categories(self, info: strawberry.Info) -> List[Category]:
        session: AsyncSession = info.context.db
        result = await session.execute(sa.select(SQLA_Category))
        return result.scalars().all()

    @strawberry.field
    async def sellers(self, info: strawberry.Info) -> List[Seller]:
        session: AsyncSession = info.context.db
        result = await session.execute(sa.select(SQLA_Seller))
        return result.scalars().all()

# --- GraphQL Schema ---
schema = strawberry.Schema(query=Query)

